use soroban_sdk::{Address,BytesN,Env,Vec};use crate::types::*;use crate::payout;use common::{math,pause};use common::reentrancy::{self,ReentrancyGuard};
pub fn init(env:&Env,admin:&Address,factory:&Address,config:&CircleConfig){if config.max_members<2||config.contribution_amount<=0||config.total_rounds==0||config.payout_type>3{panic!("invalid config");}let circle=Circle{id:env.current_contract_address(),name:config.name.clone(),organizer:config.organizer.clone(),factory:factory.clone(),contribution_amount:config.contribution_amount,max_members:config.max_members,member_count:0,payout_type:config.payout_type,total_rounds:config.total_rounds,current_round:0,status:STATUS_PENDING,started_at:0,created_at:env.ledger().timestamp(),contribution_deadline_seconds:config.contribution_deadline_seconds,min_moi_score:config.min_moi_score,collateral_amount:config.collateral_amount,penalty_bps:config.penalty_bps,grace_period_seconds:config.grace_period_seconds,max_strikes:config.max_strikes,payout_bitmap:0,total_payouts:0,total_fees:0,slug:config.slug.clone()};env.storage().instance().set(&DataKey::Circle,&circle);env.storage().instance().set(&DataKey::Admin,admin);env.storage().instance().set(&DataKey::Factory,factory);env.storage().instance().set(&DataKey::Paused,&false);env.storage().persistent().set(&DataKey::Members,&Vec::<Member>::new(env));env.storage().persistent().set(&DataKey::Contributions,&Vec::<Contribution>::new(env));env.storage().persistent().set(&DataKey::Payouts,&Vec::<PayoutRecipient>::new(env));env.storage().persistent().set(&DataKey::Bids,&Vec::<AuctionBid>::new(env));env.storage().persistent().set(&DataKey::Votes,&Vec::<VoteEntry>::new(env));}
pub fn join(env:&Env,member:&Address)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;member.require_auth();let mut circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status==STATUS_DISPUTED||circle.status==STATUS_COMPLETED||circle.status==3u32{return Err(CircleError::NotActive);}let mut members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).unwrap_or_else(||Vec::new(env));for i in 0..members.len(){if members.get(i).unwrap().address==*member{return Err(CircleError::AlreadyMember);}}if members.len()as u32>=circle.max_members{return Err(CircleError::CircleFull);}let now=env.ledger().timestamp();let pos=members.len()as u32;members.push_back(Member{address:member.clone(),position:pos,joined_at:now,strikes:0,status:MEMBER_ACTIVE,exited_at:0,total_contributions:0,total_received:0});circle.member_count=circle.member_count.wrapping_add(1);if circle.member_count>=circle.max_members&&circle.status==STATUS_PENDING{circle.status=STATUS_ACTIVE;circle.started_at=now;}env.storage().instance().set(&DataKey::Circle,&circle);env.storage().persistent().set(&DataKey::Members,&members);MemberJoined{member:member.clone(),position:pos}.publish(env);Ok(())}
pub fn contribute(env:&Env,member:&Address,amount:i128,round:u32)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;member.require_auth();let circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status!=STATUS_ACTIVE{return Err(CircleError::NotActive);}if round!=circle.current_round{return Err(CircleError::RoundNotCurrent);}if amount!=circle.contribution_amount{return Err(CircleError::ContributionMismatch);}let members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).ok_or(CircleError::NotInitialized)?;let mut found=false;for i in 0..members.len(){let m=members.get(i).unwrap();if m.address==*member{if m.status!=MEMBER_ACTIVE{return Err(CircleError::InvalidMemberStatus);}found=true;}}if!found{return Err(CircleError::NotMember);}let mut contributions:Vec<Contribution>=env.storage().persistent().get(&DataKey::Contributions).unwrap_or_else(||Vec::new(env));for i in 0..contributions.len(){let c=contributions.get(i).unwrap();if c.member==*member&&c.round==round{return Err(CircleError::AlreadyContributed);}}let now=env.ledger().timestamp();let on_time=now<=circle.started_at.wrapping_add(circle.contribution_deadline_seconds);contributions.push_back(Contribution{member:member.clone(),round,amount,timestamp:now,on_time});env.storage().persistent().set(&DataKey::Contributions,&contributions);ContributionRecorded{member:member.clone(),round,amount,on_time}.publish(env);Ok(())}
pub fn trigger_payout(env:&Env,_caller:&Address,round:u32)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;let mut circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status!=STATUS_ACTIVE{return Err(CircleError::NotActive);}if round!=circle.current_round{return Err(CircleError::RoundNotCurrent);}let(recipient,payout_type)=match circle.payout_type{PAYOUT_RANDOM=>(payout::resolve_random(env,&circle,round)?,PAYOUT_RANDOM),PAYOUT_FIXED=>(payout::resolve_fixed(env,&circle,round)?,PAYOUT_FIXED),PAYOUT_AUCTION=>{let(w,_)=payout::resolve_auction(env,&circle,round)?;(w,PAYOUT_AUCTION)}PAYOUT_VOTE=>(payout::resolve_vote(env,&circle,round)?,PAYOUT_VOTE),_=>return Err(CircleError::InvalidPayoutType)};let pool=math::safe_mul(circle.contribution_amount,circle.member_count as i128).map_err(|_|CircleError::InvalidAmount)?;let(net,fee)=math::apply_fee(pool,50).map_err(|_|CircleError::InvalidAmount)?;let now=env.ledger().timestamp();let mut payouts:Vec<PayoutRecipient>=env.storage().persistent().get(&DataKey::Payouts).unwrap_or_else(||Vec::new(env));payouts.push_back(PayoutRecipient{recipient:recipient.clone(),round,amount:net,fee,payout_type,timestamp:now});circle.current_round=circle.current_round.wrapping_add(1);circle.total_payouts=math::safe_add(circle.total_payouts,net).map_err(|_|CircleError::InvalidAmount)?;circle.total_fees=math::safe_add(circle.total_fees,fee).map_err(|_|CircleError::InvalidAmount)?;if circle.current_round>=circle.total_rounds{circle.status=STATUS_COMPLETED;}let mut members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).ok_or(CircleError::NotInitialized)?;for i in 0..members.len(){let mut m=members.get(i).unwrap();if m.address==recipient{m.total_received=math::safe_add(m.total_received,net).map_err(|_|CircleError::InvalidAmount)?;members.set(i,m);}}env.storage().instance().set(&DataKey::Circle,&circle);env.storage().persistent().set(&DataKey::Payouts,&payouts);env.storage().persistent().set(&DataKey::Members,&members);PayoutExecuted{recipient,round,amount:net,fee,payout_type}.publish(env);if circle.status==STATUS_COMPLETED{CircleCompleted{total_payouts:circle.total_payouts}.publish(env);}Ok(())}
pub fn auction_bid(env:&Env,bidder:&Address,discount_bips:u32,round:u32)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;bidder.require_auth();let circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.payout_type!=PAYOUT_AUCTION{return Err(CircleError::InvalidPayoutType);}if discount_bips>10000{return Err(CircleError::InvalidBid);}if round!=circle.current_round{return Err(CircleError::RoundNotCurrent);}let mut bids:Vec<AuctionBid>=env.storage().persistent().get(&DataKey::Bids).unwrap_or_else(||Vec::new(env));for i in 0..bids.len(){let b=bids.get(i).unwrap();if b.bidder==*bidder&&b.round==round{return Err(CircleError::AlreadyBidded);}}bids.push_back(AuctionBid{bidder:bidder.clone(),discount_bips,round,timestamp:env.ledger().timestamp()});env.storage().persistent().set(&DataKey::Bids,&bids);AuctionBidPlaced{bidder:bidder.clone(),discount_bips,round}.publish(env);Ok(())}
pub fn vote_payout(env:&Env,voter:&Address,vote_for:&Address,round:u32)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;voter.require_auth();let circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.payout_type!=PAYOUT_VOTE{return Err(CircleError::InvalidPayoutType);}if round!=circle.current_round{return Err(CircleError::RoundNotCurrent);}let members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).ok_or(CircleError::NotInitialized)?;let mut is_member=false;for i in 0..members.len(){let m=members.get(i).unwrap();if m.address==*voter{if m.status!=MEMBER_ACTIVE{return Err(CircleError::InvalidMemberStatus);}is_member=true;}}if!is_member{return Err(CircleError::NotMember);}let mut votes:Vec<VoteEntry>=env.storage().persistent().get(&DataKey::Votes).unwrap_or_else(||Vec::new(env));for i in 0..votes.len(){let v=votes.get(i).unwrap();if v.voter==*voter&&v.round==round{return Err(CircleError::AlreadyVoted);}}votes.push_back(VoteEntry{voter:voter.clone(),vote_for:vote_for.clone(),round,timestamp:env.ledger().timestamp()});env.storage().persistent().set(&DataKey::Votes,&votes);VoteCast{voter:voter.clone(),vote_for:vote_for.clone(),round}.publish(env);Ok(())}
pub fn exit(env:&Env,member:&Address)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;member.require_auth();let circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status==STATUS_COMPLETED||circle.status==3u32{return Err(CircleError::NotActive);}let mut members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).ok_or(CircleError::NotInitialized)?;let mut penalty:i128=0;for i in 0..members.len(){let mut m=members.get(i).unwrap();if m.address==*member{if m.status!=MEMBER_ACTIVE{return Err(CircleError::InvalidMemberStatus);}let contributions:Vec<Contribution>=env.storage().persistent().get(&DataKey::Contributions).unwrap_or_else(||Vec::new(env));let mut ctotal:i128=0;for j in 0..contributions.len(){let c=contributions.get(j).unwrap();if c.member==*member{ctotal=math::safe_add(ctotal,c.amount).map_err(|_|CircleError::InvalidAmount)?;}}penalty=math::calculate_percentage(ctotal,500).map_err(|_|CircleError::InvalidAmount)?;m.status=MEMBER_EXITED;m.exited_at=env.ledger().timestamp();members.set(i,m);}}env.storage().persistent().set(&DataKey::Members,&members);MemberExited{member:member.clone(),penalty}.publish(env);Ok(())}
pub fn report_late(env:&Env,_reporter:&Address,late_member:&Address,round:u32)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;let circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status!=STATUS_ACTIVE{return Err(CircleError::NotActive);}let contributions:Vec<Contribution>=env.storage().persistent().get(&DataKey::Contributions).unwrap_or_else(||Vec::new(env));let mut found=false;for i in 0..contributions.len(){let c=contributions.get(i).unwrap();if c.member==*late_member&&c.round==round&&!c.on_time{found=true;}}if!found{return Err(CircleError::NotMember);}let mut members:Vec<Member>=env.storage().persistent().get(&DataKey::Members).ok_or(CircleError::NotInitialized)?;for i in 0..members.len(){let mut m=members.get(i).unwrap();if m.address==*late_member{m.strikes=m.strikes.wrapping_add(1);if m.strikes>=circle.max_strikes{m.status=MEMBER_DEFAULTED;MemberDefaulted{member:late_member.clone(),strikes:m.strikes}.publish(env);}members.set(i,m);}}env.storage().persistent().set(&DataKey::Members,&members);Ok(())}
pub fn raise_dispute(env:&Env,member:&Address,evidence_hash:&BytesN<32>)->Result<(),CircleError>{pause::when_not_paused(env).map_err(|_|CircleError::ContractPaused)?;let _guard = ReentrancyGuard::new(env).map_err(|_| CircleError::NotActive)?;member.require_auth();let mut circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;if circle.status==STATUS_DISPUTED{return Err(CircleError::DisputeAlreadyRaised);}if env.storage().persistent().get::<DataKey,DisputeEntry>(&DataKey::Dispute).is_some(){return Err(CircleError::DisputeAlreadyRaised);}circle.status=STATUS_DISPUTED;env.storage().instance().set(&DataKey::Circle,&circle);env.storage().persistent().set(&DataKey::Dispute,&DisputeEntry{raised_by:member.clone(),evidence_hash:evidence_hash.clone(),raised_at:env.ledger().timestamp(),resolved_at:0,resolution:0,resolved_by:env.current_contract_address()});DisputeRaised{member:member.clone(),evidence_hash:evidence_hash.clone()}.publish(env);Ok(())}
pub fn resolve_dispute(env:&Env,admin:&Address,resolution:u32)->Result<(),CircleError>{admin.require_auth();let s:Address=env.storage().instance().get(&DataKey::Admin).ok_or(CircleError::NotInitialized)?;if admin!=&s{return Err(CircleError::Unauthorized);}let mut circle:Circle=env.storage().instance().get(&DataKey::Circle).ok_or(CircleError::NotInitialized)?;let mut dispute:DisputeEntry=env.storage().persistent().get(&DataKey::Dispute).ok_or(CircleError::NoActiveDispute)?;if resolution>RESOLVE_FORCE_PAYOUT{return Err(CircleError::InvalidAmount);}match resolution{RESOLVE_DISMISS|RESOLVE_FORCE_PAYOUT=>circle.status=STATUS_ACTIVE,_=>circle.status=3u32}dispute.resolved_at=env.ledger().timestamp();dispute.resolution=resolution;dispute.resolved_by=admin.clone();env.storage().instance().set(&DataKey::Circle,&circle);env.storage().persistent().set(&DataKey::Dispute,&dispute);if circle.status==3u32{CircleCancelled{dummy:0}.publish(env);}Ok(())}
pub fn get_status(env:&Env)->Circle{env.storage().instance().get(&DataKey::Circle).unwrap_or(Circle{id:env.current_contract_address(),name:soroban_sdk::String::from_str(env,""),organizer:env.current_contract_address(),factory:env.current_contract_address(),contribution_amount:0,max_members:0,member_count:0,payout_type:0,total_rounds:0,current_round:0,status:3,started_at:0,created_at:0,contribution_deadline_seconds:0,min_moi_score:0,collateral_amount:0,penalty_bps:0,grace_period_seconds:0,max_strikes:0,payout_bitmap:0,total_payouts:0,total_fees:0,slug:soroban_sdk::String::from_str(env,"")})}
pub fn get_members(env:&Env)->Vec<Member>{env.storage().persistent().get(&DataKey::Members).unwrap_or_else(||Vec::new(env))}
pub fn get_contributions(env:&Env,member:&Address)->Vec<Contribution>{let all:Vec<Contribution>=env.storage().persistent().get(&DataKey::Contributions).unwrap_or_else(||Vec::new(env));let mut out=Vec::new(env);for i in 0..all.len(){let c=all.get(i).unwrap();if c.member==*member{out.push_back(c);}}out}
pub fn pause(env:&Env,admin:&Address)->Result<(),CircleError>{let s:Address=env.storage().instance().get(&DataKey::Admin).ok_or(CircleError::NotInitialized)?;if admin!=&s{return Err(CircleError::Unauthorized);}pause::pause(env,admin).map_err(|_|CircleError::ContractPaused)}
pub fn unpause(env:&Env,admin:&Address)->Result<(),CircleError>{let s:Address=env.storage().instance().get(&DataKey::Admin).ok_or(CircleError::NotInitialized)?;if admin!=&s{return Err(CircleError::Unauthorized);}pause::unpause(env,admin).map_err(|_|CircleError::ContractPaused)}
